3_real_world_example.code:
const appName = 'SkillSprint'; // Global scope

function dashboard() {
  const section = 'Analytics'; // dashboard scope

  function renderTitle() {
    // Scope chain lookup:
    // 1. renderTitle scope  — no 'section', no 'appName'
    // 2. dashboard scope    — found 'section'!
    // 3. global scope       — found 'appName'!
    console.log(`${appName} > ${section}`);
  }

  renderTitle();
}

dashboard(); // 'SkillSprint > Analytics'

